SELECT * FROM ADMIN_USERS
WHERE  username   = #{username}
  AND  deleted_yn = 'N'

SELECT * FROM ADMIN_USERS
WHERE  admin_id   = #{adminId}
  AND  deleted_yn = 'N'

SELECT user_id, name, email, phone, birth_date, status_code, credit_score, last_login_at, created_at FROM USERS WHERE deleted_yn = 'N'
AND name LIKE '%' || #{name} || '%'
AND email LIKE '%' || #{email} || '%'
AND phone LIKE '%' || #{phone} || '%'
AND status_code = #{statusCode}
AND birth_date >= #{birthDateFrom}
AND birth_date <= #{birthDateTo}
ORDER BY created_at DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(1) FROM USERS
WHERE  deleted_yn = 'N'

  AND name  LIKE '%' || #{name}  || '%'


  AND email LIKE '%' || #{email} || '%'


  AND phone LIKE '%' || #{phone} || '%'


  AND status_code = #{statusCode}


  AND birth_date >= #{birthDateFrom}


  AND birth_date <= #{birthDateTo}

SELECT * FROM USERS
WHERE  user_id    = #{userId}
  AND  deleted_yn = 'N'

