UPDATE ADMIN_USERS
SET    login_fail_count = login_fail_count + 1
WHERE  admin_id = #{adminId}

UPDATE ADMIN_USERS
SET    locked_until = #{lockedUntil}
WHERE  admin_id = #{adminId}

UPDATE ADMIN_USERS
SET    last_login_at = #{lastLoginAt}
WHERE  admin_id = #{adminId}
